    15	
    16	function renderArtifact(args: {
    17	  sourceTicketId: string
    18	  evidenceTicketId: string
    19	  evidenceArtifactPath: string
    20	  reason: string
    21	}): string {
    22	  return `# Ticket Reverification
    23	
    24	## Source Ticket
    25	
    26	- ${args.sourceTicketId}
    27	
    28	## Evidence
    29	
    30	- evidence_ticket_id: ${args.evidenceTicketId}
    31	- evidence_artifact_path: ${args.evidenceArtifactPath}
    32	
    33	## Reason
    34	
    35	${args.reason}
    36	
    37	## Result
    38	
    39	Overall Result: PASS
    40	`
    41	}
    42	
    43	export default tool({
    44	  description: "Restore trust for a completed historical ticket after follow-up remediation or backlog reverification completes.",
    45	  args: {
    46	    ticket_id: tool.schema.string().describe("Historical source ticket whose trust should be restored."),
    47	    evidence_artifact_path: tool.schema.string().describe("Current artifact path proving the reverification outcome."),
    48	    evidence_ticket_id: tool.schema.string().describe("Ticket that owns the evidence artifact. Defaults to the source ticket.").optional(),
    49	    reason: tool.schema.string().describe("Why this evidence is sufficient to restore trust.").optional(),
    50	  },
    51	  async execute(args) {
    52	    const manifest = await loadManifest()
    53	    const workflow = await loadWorkflowState()
    54	    const sourceTicket = getTicket(manifest, args.ticket_id)
    55	    const evidenceTicket = getTicket(manifest, args.evidence_ticket_id || sourceTicket.id)
    56	    const evidencePath = normalizeRepoPath(args.evidence_artifact_path)
    57	    const reason = typeof args.reason === "string" && args.reason.trim()
    58	      ? args.reason.trim()
    59	      : `Trust restored from ${evidenceTicket.id} using ${evidencePath}.`
    60	
    61	    if (sourceTicket.status !== "done") {
    62	      throw new Error(`Ticket ${sourceTicket.id} must remain historically done before it can be reverified.`)
    63	    }
    64	    if (
    65	      evidenceTicket.id !== sourceTicket.id &&
    66	      evidenceTicket.source_ticket_id !== sourceTicket.id &&
    67	      !sourceTicket.follow_up_ticket_ids.includes(evidenceTicket.id)
    68	    ) {
    69	      throw new Error(`Evidence ticket ${evidenceTicket.id} is not linked to source ticket ${sourceTicket.id}.`)
    70	    }
    71	    if (evidenceTicket.id !== sourceTicket.id && evidenceTicket.status !== "done") {
    72	      throw new Error(`Evidence ticket ${evidenceTicket.id} must be done before it can restore trust for ${sourceTicket.id}.`)
    73	    }
    74	
    75	    const evidenceArtifact = evidenceTicket.artifacts.find(
    76	      (artifact) => artifact.path === evidencePath && artifact.trust_state === "current",
    77	    ) as Artifact | undefined
    78	    if (!evidenceArtifact) {
    79	      throw new Error(`Evidence artifact ${evidencePath} is not a current artifact on ticket ${evidenceTicket.id}.`)
    80	    }
    81	
    82	    const registry = await loadArtifactRegistry()
    83	    const canonicalPath = normalizeRepoPath(defaultArtifactPath(sourceTicket.id, "review", "reverification"))
    84	    await writeText(
    85	      canonicalPath,
    86	      renderArtifact({
    87	        sourceTicketId: sourceTicket.id,
    88	        evidenceTicketId: evidenceTicket.id,
    89	        evidenceArtifactPath: evidencePath,
    90	        reason,
    91	      }),
    92	    )
    93	    const reverificationArtifact = await registerArtifactSnapshot({
    94	      ticket: sourceTicket,
    95	      registry,
    96	      source_path: canonicalPath,
    97	      kind: "reverification",
    98	      stage: "review",
    99	      summary: `Trust restored using ${evidenceTicket.id}.`,
   100	    })
   101	
   102	    sourceTicket.verification_state = "reverified"
   103	    getTicketWorkflowState(workflow, sourceTicket.id).needs_reverification = false
   104	
   105	    await saveWorkflowBundle({ workflow, manifest, registry })
   106	
   107	    return JSON.stringify(
   108	      {
   109	        ticket_id: sourceTicket.id,
   110	        verification_state: sourceTicket.verification_state,
   111	        reverification_artifact: reverificationArtifact.path,
   112	        evidence_ticket_id: evidenceTicket.id,
   113	        evidence_artifact_path: evidencePath,
   114	      },
   115	      null,
   116	      2,
   117	    )
   118	  },
   119	})

